const scans = $input.all();
const allTeasers = [];

scans.forEach(scan => {
  let titles = scan.json.competitor_titles;
  if (typeof titles === 'string') {
    try { titles = JSON.parse(titles); } catch(e) { titles = []; }
  }
  if (Array.isArray(titles)) {
    titles.forEach(t => {
      allTeasers.push({
        title: t.title || '',
        url: t.url || '',
        position: t.position || 0,
        site: scan.json.site_url
      });
    });
  }
});

// Deduplicate by title
const seen = new Set();
const unique = allTeasers.filter(t => {
  if (!t.title || t.title.length < 10 || seen.has(t.title)) return false;
  seen.add(t.title);
  return true;
});

// Take top competitors by frequency
return [{
  json: {
    total_unique_teasers: unique.length,
    competitor_titles: unique.slice(0, 30).map(t => t.title),
    sample_teasers: unique.slice(0, 30)
  }
}];

