const claudeResponse = $input.first().json;
const competitorData = $('Aggregate Competitor Data').first().json;

const analysis = claudeResponse.content?.[0]?.text || 'Analysis failed';

// Save unique competitors to DB
const competitors = competitorData.sample_teasers || [];

return [{
  json: {
    analysis: analysis,
    competitors_count: competitorData.total_unique_teasers,
    competitors: competitors
  }
}];

